using RestSharp;
using Newtonsoft;
using UBSInterfaceToolkit.TokenToolkit;

internal final class UBSOutboundInterfaceToolkit
{
}

Method.Source:
    public static str getBearer()
    {
        UBSOutboundInterface outboundInterface =  UBSOutboundInterface::findUBSOutboundInterface();

        str bearer = UBSInterfaceToolkit.TokenToolkit::getToken(outboundInterface.UBSRootURLAuthentication,
                                                                outboundInterface.UBSTenantId,
                                                                outboundInterface.UBSEndURLAuthentication,
                                                                outboundInterface.UBSClientId,
                                                                UBSOutboundInterface::findPassword(),
                                                                outboundInterface.UBSGrantType,
                                                                outboundInterface.UBSScope);

        return bearer;
    }
